// ---------------------------------------------------------------------------
// Mock handler helpers
// ---------------------------------------------------------------------------

function odata(body: unknown): ODataParams {
  return (body ?? {}) as ODataParams;
}
function person(filter: string): string {
  return /person_id eq '([^']+)'/.exec(filter)?.[1] ?? 'p1';
}
function team(filter: string): string {
  return /org_unit_id eq '([^']+)'/.exec(filter)?.[1] ?? 'backend';
}
function wrap<T>(items: T[]): ODataResponse<T> {
  return { items, page_info: { has_next: false, cursor: null } };
}
function drillId(filter: string): string {
  return /drill_id eq '([^']+)'/.exec(filter)?.[1] ?? '';
}

/**
 * Deterministic seed derived from $filter string.
 * Different filter strings produce different (but stable) variation offsets,
 * so mock data varies per period/team/person but stays reproducible.
 */
function filterSeed(filter: string): number {
  let h = 0;
  for (let i = 0; i < filter.length; i++) {
    h = ((h << 5) - h + filter.charCodeAt(i)) | 0;
  }
  return Math.abs(h);
}

/** Deterministic pseudo-random variation based on index */
function vary(base: number, index: number, spread: number): number {
  const hash = Math.sin(index * 9301 + 49297) * 49297;
  const factor = (hash - Math.floor(hash)) * 2 - 1; // -1 to 1
  return Math.round((base + factor * spread) * 10) / 10;
}

// ---------------------------------------------------------------------------
// Caching -- factory-generated scenarios cached per key for session consistency
// ---------------------------------------------------------------------------

type IcScenarioCache = ReturnType<typeof mockIcScenario>;
const icScenarioCache = new Map<string, IcScenarioCache>();
function cachedIcScenario(personId: string): IcScenarioCache {
  let cached = icScenarioCache.get(personId);
  if (!cached) {
    cached = mockIcScenario(personId);
    icScenarioCache.set(personId, cached);
  }
  return cached;
}

// ---------------------------------------------------------------------------
// Percentile computation — from real generated IC scenarios
// ---------------------------------------------------------------------------

function computeMedian(values: number[]): number {
  if (values.length === 0) return 0;
  const sorted = [...values].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 === 1
    ? (sorted[mid] ?? 0)
    : Math.round(((sorted[mid - 1] ?? 0) + (sorted[mid] ?? 0)) * 10) / 20;
}

type MetricPercentiles = { p5: number; p25: number; p50: number; p75: number; p95: number };

function computePercentiles(values: number[]): MetricPercentiles {
  if (values.length === 0) return { p5: 0, p25: 0, p50: 0, p75: 0, p95: 0 };
  const sorted = [...values].sort((a, b) => a - b);
  const at = (p: number) => {
    const idx = (p / 100) * (sorted.length - 1);
    const lo = Math.floor(idx);
    const hi = Math.ceil(idx);
    const w = idx - lo;
    return Math.round(((sorted[lo] ?? 0) * (1 - w) + (sorted[hi] ?? 0) * w) * 10) / 10;
  };
  return { p5: at(5), p25: at(25), p50: at(50), p75: at(75), p95: at(95) };
}

/** Cached team medians: teamId → { metric_key → median value } */
const teamMedianCache = new Map<string, Map<string, number>>();

function getTeamMedians(teamId: string): Map<string, number> {
  let cached = teamMedianCache.get(teamId);
  if (cached) return cached;

  const members = teamMembers(teamId);
  const metricValues = new Map<string, number[]>();

  for (const member of members) {
    const scenario = cachedIcScenario(member.person_id);
    for (const rows of Object.values(scenario.bullets)) {
      for (const row of rows) {
        let arr = metricValues.get(row.metric_key);
        if (!arr) { arr = []; metricValues.set(row.metric_key, arr); }
        arr.push(row.value);
      }
    }
  }

  cached = new Map();
  for (const [key, values] of metricValues) {
    cached.set(key, computeMedian(values));
  }
  teamMedianCache.set(teamId, cached);
  return cached;
}

/**
 * Percentiles from a specific set of people's IC bullet scenarios.
 * Reusable for both team-scoped and company-wide distributions.
 */
function buildPercentileMap(personIds: string[]): Map<string, MetricPercentiles> {
  const metricValues = new Map<string, number[]>();
  for (const pid of personIds) {
    const scenario = cachedIcScenario(pid);
    for (const rows of Object.values(scenario.bullets)) {
      for (const row of rows) {
        let arr = metricValues.get(row.metric_key);
        if (!arr) { arr = []; metricValues.set(row.metric_key, arr); }
        arr.push(row.value);
      }
    }
  }
  const result = new Map<string, MetricPercentiles>();
  for (const [key, vals] of metricValues) {
    result.set(key, computePercentiles(vals));
  }
  return result;
}

/**
 * Team-level percentiles — used for team bullet status.
 * Each team contributes ONE data point per metric (its own median),
 * so we compare teams against other teams — not individuals against individuals.
 *
 * For IC-mapped metrics: team value = median of members' IC scenario values.
 * For team-only metrics (prs_per_dev, active_ai_members, etc.) that have no
 * IC equivalent: team value = mockTeamBulletSection-generated value per team.
 */
let _teamLevelPercentiles: Map<string, MetricPercentiles> | null = null;

function getTeamLevelPercentiles(): Map<string, MetricPercentiles> {
  if (_teamLevelPercentiles) return _teamLevelPercentiles;

  const metricValues = new Map<string, number[]>();
  const icCoveredKeys = new Set<string>();

  // IC-mapped metrics: use real team medians (one per team, derived from IC scenarios)
  for (const t of TEAMS) {
    for (const [key, value] of getTeamMedians(t.id)) {
      icCoveredKeys.add(key);
      let arr = metricValues.get(key);
      if (!arr) { arr = []; metricValues.set(key, arr); }
      arr.push(value);
    }
  }

  // Team-only metrics: generate one value per team from mockTeamBulletSection
  const TEAM_SECTIONS = ['task_delivery', 'code_quality', 'estimation', 'ai_adoption', 'collaboration'] as const;
  for (const t of TEAMS) {
    const seed = filterSeed(t.id); // stable per team
    for (const sectionId of TEAM_SECTIONS) {
      for (const row of mockTeamBulletSection(sectionId, seed)) {
        if (!icCoveredKeys.has(row.metric_key)) {
          let arr = metricValues.get(row.metric_key);
          if (!arr) { arr = []; metricValues.set(row.metric_key, arr); }
          arr.push(row.value);
        }
      }
    }
  }

  _teamLevelPercentiles = new Map();
  for (const [key, vals] of metricValues) {
    _teamLevelPercentiles.set(key, computePercentiles(vals));
  }
  return _teamLevelPercentiles;
}

/**
 * Team-scoped percentiles — used for IC bullet STATUS thresholds (p25/p75).
 * Comparing an individual against teammates, not the whole company.
 * Teams vary in domain (bug-only, platform, greenfield), so cross-team
 * comparison would unfairly skew status for specialists.
 */
const teamPercentileCache = new Map<string, Map<string, MetricPercentiles>>();
function getTeamPercentiles(teamId: string): Map<string, MetricPercentiles> {
  let cached = teamPercentileCache.get(teamId);
  if (!cached) {
    const memberIds = teamMembers(teamId).map((m) => m.person_id);
    cached = buildPercentileMap(memberIds);
    teamPercentileCache.set(teamId, cached);
  }
  return cached;
}

/**
 * Company-wide IC percentiles — used for DISPLAY RANGE (p5/p95, axis bounds) only.
 * All people across all teams → wide, stable range that doesn't collapse
 * when comparing against a small team of 5–6 members.
 * Separate from status thresholds, which are team-scoped.
 */
let _companyIcPercentiles: Map<string, MetricPercentiles> | null = null;
function getCompanyIcPercentiles(): Map<string, MetricPercentiles> {
  if (!_companyIcPercentiles) {
    _companyIcPercentiles = buildPercentileMap(PEOPLE.map((p) => p.person_id));
  }
  return _companyIcPercentiles;
}

/** Find person's team_id from registry */
function personTeam(personId: string): string {
  return PEOPLE_BY_ID[personId]?.team_id ?? 'backend';
}

/**
 * Inject percentiles and team median into raw bullet rows.
 * Clones rows to avoid mutating cached scenario objects.
 *
 * @param percentilesMap - company-wide for team bullets, team-scoped for IC bullets
 */
/**
 * Inject display range and status thresholds into IC bullet rows.
 * - p5/p95 (axis bounds):  company-wide IC distribution → wide, stable
 * - p25/p75 (status):      team-scoped distribution → fair peer comparison
 * - median:                team median → "where is my team?"
 */
function applyStats(
  rows: RawBulletAggregateRow[],
  teamId: string,
  statusPercentilesMap: Map<string, MetricPercentiles>,
): RawBulletAggregateRow[] {
  const medians = getTeamMedians(teamId);
  const companyPcts = getCompanyIcPercentiles();
  return rows.map((r) => {
    const disp = companyPcts.get(r.metric_key);
    const stat = statusPercentilesMap.get(r.metric_key);
    const realMedian = medians.get(r.metric_key);
    return {
      ...r,
      ...(disp && { p5: disp.p5, p95: disp.p95 }),
      ...(stat && { p25: stat.p25, p75: stat.p75 }),
      ...(realMedian !== undefined && { median: realMedian }),
    };
  });
}

/** Returns true when the OData filter describes a previous-period range (end date is in the past). */
function isPrevPeriodFilter(filter: string): boolean {
  const m = /metric_date lt '(\d{4}-\d{2}-\d{2})'/.exec(filter);
  if (!m) return false;
  const endDate = new Date(m[1]);
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  return endDate <= today;
}

// ---------------------------------------------------------------------------
// IC drill generator -- simple inline drill data per drill type
// ---------------------------------------------------------------------------

function generateDrill(did: string, personId: string): DrillData {
  const seed = filterSeed(`${did}:${personId}`);
  const pid = parseInt(personId.replace('p', ''), 10) || 1;
  const login = `user.${personId}`;

  const date = (total: number, i: number): string =>
    `2026-03-${String(Math.max(1, 31 - Math.round((i * 28) / Math.max(total, 1)))).padStart(2, '0')}`;

  const drillDefs: Record<string, () => DrillData> = {
    'tasks-completed': () => {
      const count = Math.max(3, 5 + Math.round(vary(7, seed, 5)));
      const rows: DrillRow[] = Array.from({ length: count }, (_, i) => ({
        Task: `INSIGHT-${300 + pid * 20 - i * 7}`,
        'Story Points': [1, 2, 3, 5, 3, 2, 1, 5][i % 8] as number,
        'Dev Time': `${Math.max(4, 12 + ([-2, 0, 2, -4, 4, -2, 0, 2][i % 8] as number))}h`,
        Closed: date(count, i),
      }));
      return {
        title: 'Tasks Completed', source: 'Jira', srcClass: 'bg-blue-600',
        value: String(count),
        filter: `assignee = ${login} AND status = Done AND updatedDate >= -30d`,
        columns: ['Task', 'Story Points', 'Dev Time', 'Closed'],
        rows,
      };
    },
    'cycle-time': () => {
      const devTime = Math.max(8, Math.round(vary(14, seed, 6)));
      const count = Math.max(2, Math.round(vary(5, seed, 2)));
      const rows: DrillRow[] = Array.from({ length: count }, (_, i) => ({
        Task: `INSIGHT-${280 + pid * 15 - i * 6}`,
        'Story Points': [3, 2, 5, 1, 3][i % 5] as number,
        'Dev Time': `${devTime + ([-2, 0, 2, -4, 4][i % 5] as number)}h`,
        Status: i === 0 ? 'In Progress' : 'Done',
      }));
      return {
        title: 'Task Development Time', source: 'Jira', srcClass: 'bg-blue-600',
        value: `${devTime}h`,
        filter: `assignee = ${login} AND status changed to "In Progress"`,
        columns: ['Task', 'Story Points', 'Dev Time', 'Status'],
        rows,
      };
    },
    'task-reopen': () => {
      const reopened = seed % 3 === 0 ? 1 : 0;
      return {
        title: 'Reopened Tasks', source: 'Jira', srcClass: 'bg-blue-600',
        value: String(reopened),
        filter: `assignee = ${login} AND status changed from Done to "In Progress" after -14d`,
        columns: ['Task', 'Reason', 'Reopened', 'Resolved'],
        rows: reopened > 0
          ? [{ Task: `INSIGHT-${270 + pid * 5}`, Reason: 'QA regression', Reopened: '2026-03-20', Resolved: '2026-03-21' }]
          : [],
      };
    },
    'commits': () => {
      const count = Math.max(5, Math.round(vary(28, seed, 12)));
      const shown = Math.min(count, 20);
      const rows: DrillRow[] = Array.from({ length: shown }, (_, i) => ({
        Commit: `${personId}${String(i).padStart(3, '0')}x`,
        Repository: ['insight-front', 'insight-api', 'insight-shared'][i % 3] as string,
        '+LOC': Math.round((50 + i * 15) * 1.2),
        '-LOC': Math.round(10 + i * 4),
        Date: date(shown, i),
      }));
      return {
        title: 'Commits', source: 'Bitbucket', srcClass: 'bg-blue-800',
        value: String(count),
        filter: `author = ${login} AND date >= 2026-03-01${count > 20 ? ' (showing last 20)' : ''}`,
        columns: ['Commit', 'Repository', '+LOC', '-LOC', 'Date'],
        rows,
      };
    },
    'pull-requests': () => {
      const count = Math.max(2, Math.round(vary(8, seed, 4)));
      const rows: DrillRow[] = Array.from({ length: count }, (_, i) => ({
        PR: `PR #${500 + pid * 10 - i * 5}`,
        Repository: ['insight-front', 'insight-api', 'insight-shared'][i % 3] as string,
        Status: i === count - 1 && count > 1 ? 'Open' : 'Merged',
        'Cycle Time': i === count - 1 && count > 1 ? '\u2014' : `${Math.max(8, Math.round(vary(16, seed + i, 6)))}h`,
      }));
      return {
        title: 'Pull Requests', source: 'Bitbucket', srcClass: 'bg-blue-800',
        value: String(count),
        filter: `author = ${login} AND created >= 2026-03-01`,
        columns: ['PR', 'Repository', 'Status', 'Cycle Time'],
        rows,
      };
    },
    'reviews': () => {
      const count = Math.max(2, Math.round(vary(10, seed, 5)));
      const reviewers = PEOPLE.map((p) => p.name);
      const rows: DrillRow[] = Array.from({ length: count }, (_, i) => ({
        PR: `PR #${550 + pid * 8 - i * 4}`,
        Author: reviewers[i % reviewers.length] as string,
        Outcome: i % 3 === 1 ? 'Changes Requested' : 'Approved',
        'Time to Review': `${1 + (i % 6)}h`,
      }));
      return {
        title: 'Code Reviews Given', source: 'Bitbucket', srcClass: 'bg-blue-800',
        value: String(count),
        filter: `reviewer = ${login} AND reviewed >= 2026-03-01`,
        columns: ['PR', 'Author', 'Outcome', 'Time to Review'],
        rows,
      };
    },
    'builds': () => {
      const buildPct = Math.min(100, Math.max(70, Math.round(vary(94, seed, 6))));
      return {
        title: 'Build Results', source: 'CI', srcClass: 'bg-gray-600',
        value: `${buildPct}%`,
        filter: `author = ${login} AND build.date >= 2026-03-01`,
        columns: ['Build', 'Branch', 'Status', 'Duration'],
        rows: [
          { Build: `build-${1000 + pid * 10 + 2}`, Branch: 'feat/main-feature', Status: 'Passed',                             Duration: '3m 12s' },
          { Build: `build-${1000 + pid * 10 + 1}`, Branch: 'feat/main-feature', Status: buildPct < 90 ? 'Failed' : 'Passed',   Duration: '2m 08s' },
          { Build: `build-${1000 + pid * 10}`,     Branch: 'fix/bug-fix',       Status: 'Passed',                             Duration: '3m 01s' },
        ],
      };
    },
    'bugs-fixed': () => {
      const count = Math.max(1, Math.round(vary(5, seed, 3)));
      const rows: DrillRow[] = Array.from({ length: count }, (_, i) => ({
        Bug: `INSIGHT-${200 + pid * 15 - i * 8}`,
        Priority: (['High', 'Medium', 'Low', 'Critical', 'Medium', 'High'][i % 6]) as string,
        'Fix Time': `${Math.max(1, Math.round(vary(6, seed + i, 3)))}h`,
        Closed: date(count, i),
      }));
      return {
        title: 'Bugs Fixed', source: 'Jira', srcClass: 'bg-blue-600',
        value: String(count),
        filter: `assignee = ${login} AND issuetype = Bug AND status = Done AND resolved >= 2026-03-01`,
        columns: ['Bug', 'Priority', 'Fix Time', 'Closed'],
        rows,
      };
    },
  };

  const factory = drillDefs[did];
  if (factory) return factory();

  // Fallback for unknown drill IDs
  return {
    title: did, source: 'Unknown', srcClass: 'bg-gray-400',
    value: '0', filter: '', columns: ['Info'], rows: [{ Info: 'No data available' }],
  };
}

