// ---------------------------------------------------------------------------
// Executive rows -- aggregated from IC scenarios per team
// ---------------------------------------------------------------------------

function execRowsFromIcScenarios(): RawExecSummaryRow[] {
  return TEAMS.map((t) => {
    const members = teamMembers(t.id);
    const scenarios = members.map((m) => cachedIcScenario(m.person_id).kpiAggregate);
    const n = scenarios.length || 1;
    const sum = (fn: (s: typeof scenarios[0]) => number) =>
      scenarios.reduce((acc, s) => acc + fn(s), 0);
    const avg = (fn: (s: typeof scenarios[0]) => number) =>
      Math.round(sum(fn) / n);

    // ai_adoption_pct = % of members with at least one AI tool
    const aiActiveCount = members.filter((m) => m.ai_tools.length > 0).length;

    return {
      org_unit_id: t.id,
      org_unit_name: t.name,
      headcount: members.length,
      tasks_closed: sum((s) => s.tasks_closed),
      bugs_fixed: sum((s) => s.bugs_fixed),
      build_success_pct: avg((s) => s.build_success_pct ?? 94),
      focus_time_pct: avg((s) => s.focus_time_pct),
      ai_adoption_pct: Math.round((aiActiveCount / n) * 100),
      ai_loc_share_pct: avg((s) => s.ai_loc_share_pct),
      pr_cycle_time_h: avg((s) => s.pr_cycle_time_h),
    };
  });
}

// ---------------------------------------------------------------------------
// Mock map -- POST /api/analytics/v1/metrics/{uuid}/query
// ---------------------------------------------------------------------------

/**
 * Each handler receives the OData POST body, infers period / person / team from
 * $filter, and returns the matching mock data wrapped in ODataResponse.
 *
 * POST handlers use factories for raw data generation. The filter string is
 * hashed to produce deterministic variation per period/team/person.
 *
 * Legacy GET entries for dashboard/speed are retained unchanged.
 */
export const insightMockMap = {
  // Legacy screens (not yet migrated to metric queries)
  'GET /api/analytics/v1/dashboard': (): DashboardData => mockDashboardData,
  'GET /api/analytics/v1/speed':     (): SpeedData => mockSpeedData,

  // Executive summary -- aggregated from IC scenario data per team
  [`POST /api/analytics/v1/metrics/${METRIC_REGISTRY.EXEC_SUMMARY}/query`]:
    (): ODataResponse<RawExecSummaryRow> => wrap(execRowsFromIcScenarios()),

  // Team members -- returns RawTeamMemberRow[] for the requested team only.
  // Metric values are derived from each person's IC scenario (single source of truth).
  [`POST /api/analytics/v1/metrics/${METRIC_REGISTRY.TEAM_MEMBER}/query`]:
    (body: unknown): ODataResponse<RawTeamMemberRow> => {
      const f = odata(body).$filter ?? '';
      const teamId = team(f);
      return wrap(mockTeamMemberRowsForTeam(teamId).map((r) => {
        const scenario = cachedIcScenario(r.person_id);
        const ic = scenario.kpiAggregate;
        // dev_time_h is not in kpiAggregate — pull from task_dev_time bullet
        const devTimeBullet = scenario.bullets['task_delivery']
          ?.find((b) => b.metric_key === 'task_dev_time');
        return {
          ...r,
          tasks_closed: ic.tasks_closed,
          bugs_fixed: ic.bugs_fixed,
          dev_time_h: devTimeBullet ? Math.round(devTimeBullet.value) : r.dev_time_h,
          prs_merged: ic.prs_merged,
          build_success_pct: ic.build_success_pct,
          focus_time_pct: ic.focus_time_pct,
          ai_loc_share_pct: ic.ai_loc_share_pct,
        };
      }));
    },

  // Team bullet sections (delivery, quality, collab, AI) -- return RawBulletAggregateRow[]
  // Values for metrics that have matching IC bullet keys are computed as the team median
  // from member IC scenarios; others are generated from BULLET_DEFS defaults.
  ...((['TEAM_BULLET_DELIVERY', 'TEAM_BULLET_QUALITY', 'TEAM_BULLET_COLLAB', 'TEAM_BULLET_AI'] as const).reduce<
    Record<string, (body: unknown) => ODataResponse<RawBulletAggregateRow>>
  >((acc, key) => {
    const sectionMap: Record<typeof key, string> = {
      TEAM_BULLET_DELIVERY: 'task_delivery',
      TEAM_BULLET_QUALITY:  'code_quality',
      TEAM_BULLET_COLLAB:   'collaboration',
      TEAM_BULLET_AI:       'ai_adoption',
    };
    const sectionId = sectionMap[key];
    acc[`POST /api/analytics/v1/metrics/${METRIC_REGISTRY[key]}/query`] =
      (body: unknown): ODataResponse<RawBulletAggregateRow> => {
        const f = odata(body).$filter ?? '';
        const teamId = team(f);
        const seed = filterSeed(f);
        const rows = mockTeamBulletSection(sectionId, seed);
        const teamMedians = getTeamMedians(teamId);
        const teamLevelPcts = getTeamLevelPercentiles();
        const companyIcPcts = getCompanyIcPercentiles();
        // Team bullet:
        //   p5/p95 (axis):    company IC distribution → wide; fallback to team-level for team-only metrics
        //   p25/p75 (status): cross-team distribution → compare teams to teams
        //   value:            this team's median; median marker: cross-team p50
        return wrap(rows.map((r) => {
          const teamMedian = teamMedians.get(r.metric_key);
          const tlPcts = teamLevelPcts.get(r.metric_key);
          const dispPcts = companyIcPcts.get(r.metric_key) ?? tlPcts;
          return {
            ...r,
            ...(dispPcts && { p5: dispPcts.p5, p95: dispPcts.p95 }),
            ...(tlPcts && { p25: tlPcts.p25, p75: tlPcts.p75 }),
            ...(teamMedian !== undefined && { value: teamMedian }),
            median: tlPcts?.p50 ?? null,
          };
        }));
      };
    return acc;
  }, {})),

  // IC KPIs -- returns RawIcAggregateRow[]
  // Chooses current vs previous aggregate by inspecting the date range in $filter.
  // A filter whose end date (metric_date lt) is already in the past is a previous-period request.
  //
  // KNOWN MOCK LIMITATION: IC KPI values do not vary across week/month/quarter/year periods.
  // The mock returns the same scenario.kpiAggregate regardless of period granularity.
  // On a real backend, aggregates would differ meaningfully per period.
  // inferPeriodFromODataFilter() is available in periodToDateRange.ts if period-aware variation is added later.
  [`POST /api/analytics/v1/metrics/${METRIC_REGISTRY.IC_KPIS}/query`]:
    (body: unknown): ODataResponse<RawIcAggregateRow> => {
      const f = odata(body).$filter ?? '';
      const pid = person(f);
      const scenario = cachedIcScenario(pid);
      const row = isPrevPeriodFilter(f) ? scenario.prevKpiAggregate : scenario.kpiAggregate;
      return wrap([row]);
    },

  // IC bullet metrics (delivery, collab, AI tools) -- return RawBulletAggregateRow[]
  ...((['IC_BULLET_DELIVERY', 'IC_BULLET_COLLAB', 'IC_BULLET_AI'] as const).reduce<
    Record<string, (body: unknown) => ODataResponse<RawBulletAggregateRow>>
  >((acc, key) => {
    const sectionMap: Record<typeof key, readonly string[]> = {
      IC_BULLET_DELIVERY: ['task_delivery', 'git_output', 'code_quality'],
      IC_BULLET_COLLAB:   ['collab'],
      IC_BULLET_AI:       ['ai_tools'],
    };
    const sectionIds = sectionMap[key];
    // KNOWN MOCK LIMITATION: IC bullet metrics ignore the period filter entirely.
    // All periods (week/month/quarter/year) return identical scenario.bullets data.
    acc[`POST /api/analytics/v1/metrics/${METRIC_REGISTRY[key]}/query`] =
      (body: unknown): ODataResponse<RawBulletAggregateRow> => {
        const f = odata(body).$filter ?? '';
        const pid = person(f);
        const tid = personTeam(pid);
        const scenario = cachedIcScenario(pid);
        const items = sectionIds.flatMap((section) => scenario.bullets[section] ?? []);
        // IC status thresholds use team percentiles — compare against teammates,
        // not the whole company (teams differ too much in domain and tooling).
        return wrap(applyStats(items, tid, getTeamPercentiles(tid)));
      };
    return acc;
  }, {})),

  // IC chart: LOC trend -- returns RawLocTrendRow[]
  // KNOWN MOCK LIMITATION: chart data points are identical across periods.
  // Only the x-axis labels reformat (Mon/Tue for week, W1/W2 for month, etc.) via transforms.ts formatDateLabel().
  [`POST /api/analytics/v1/metrics/${METRIC_REGISTRY.IC_CHART_LOC}/query`]:
    (body: unknown): ODataResponse<RawLocTrendRow> => {
      const f = odata(body).$filter ?? '';
      const pid = person(f);
      const scenario = cachedIcScenario(pid);
      return wrap(scenario.locTrend);
    },

  // IC chart: delivery trend -- returns RawDeliveryTrendRow[]
  [`POST /api/analytics/v1/metrics/${METRIC_REGISTRY.IC_CHART_DELIVERY}/query`]:
    (body: unknown): ODataResponse<RawDeliveryTrendRow> => {
      const f = odata(body).$filter ?? '';
      const pid = person(f);
      const scenario = cachedIcScenario(pid);
      return wrap(scenario.deliveryTrend);
    },

  // IC drills -- drill_id extracted from $filter; person also from $filter
  [`POST /api/analytics/v1/metrics/${METRIC_REGISTRY.IC_DRILL}/query`]:
    (body: unknown): ODataResponse<DrillData> => {
      const f   = odata(body).$filter ?? '';
      const did = drillId(f);
      const pid = person(f);
      if (!did) return wrap([]);
      return wrap([generateDrill(did, pid)]);
    },

  // IC time-off notices -- returns empty by default (no time off scheduled)
  [`POST /api/analytics/v1/metrics/${METRIC_REGISTRY.IC_TIMEOFF}/query`]:
    (_body: unknown): ODataResponse<TimeOffNotice> => wrap([]),
} satisfies MockMap;
